class Solution:
    def minJumps(self, arr):
        from collections import defaultdict, deque
        n = len(arr)
        if n == 1:
            return 0
        groups = defaultdict(list)
        for i, v in enumerate(arr):
            groups[v].append(i)
        dist = [-1] * n
        dist[0] = 0
        q = deque([0])
        while q:
            i = q.popleft()
            d = dist[i]
            cand = []
            if i + 1 < n:
                cand.append(i + 1)
            if i - 1 >= 0:
                cand.append(i - 1)
            cand.extend(groups.get(arr[i], []))
            groups[arr[i]] = []
            for j in cand:
                if dist[j] == -1:
                    dist[j] = d + 1
                    if j == n - 1:
                        return dist[j]
                    q.append(j)
        return dist[n - 1]

