class Solution:
    def minJumps(self, arr):
        from collections import defaultdict, deque
        n = len(arr)
        if n == 1:
            return 0
        index = defaultdict(list)
        for i, v in enumerate(arr):
            index[v].append(i)
        visited = [False] * n
        visited[0] = True
        q = deque([(0, 0)])
        while q:
            i, steps = q.popleft()
            if i == n - 1:
                return steps
            neighbors = index[arr[i]]
            neighbors.append(i + 1)
            neighbors.append(i - 1)
            for j in neighbors:
                if 0 <= j < n and not visited[j]:
                    visited[j] = True
                    q.append((j, steps + 1))
            index[arr[i]] = []
        return -1

