var minJumps = function(arr) {
    const n = arr.length;
    if (n === 1) return 0;
    const index = new Map();
    for (let i = 0; i < n; i++) {
        if (!index.has(arr[i])) index.set(arr[i], []);
        index.get(arr[i]).push(i);
    }
    const visited = new Array(n).fill(false);
    visited[0] = true;
    let queue = [0];
    let steps = 0;
    while (queue.length) {
        const next = [];
        for (const i of queue) {
            if (i === n - 1) return steps;
            const neighbors = index.get(arr[i]) || [];
            neighbors.push(i + 1, i - 1);
            for (const j of neighbors) {
                if (j >= 0 && j < n && !visited[j]) {
                    visited[j] = true;
                    next.push(j);
                }
            }
            index.set(arr[i], []);
        }
        queue = next;
        steps++;
    }
    return -1;
};
